from outlines.prompts import register_filter, unregister_filter, Prompt, prompt

register_filter('shout', lambda s: s.upper() + '!')

@prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')
try:
    print(greet('world'))
except Exception as e:
    print('Expected error:', e)
"

